/**
 * Tests for src/lib/performance/image-optimization.ts
 *
 * Tests all pure utility functions: buildImageUrl, buildSrcSet,
 * buildResponsiveAttrs, generateBlurPlaceholder, computeSizes,
 * isOverBudget, estimateFormatSavings, suggestFormat.
 */

import {
  buildImageUrl,
  buildSrcSet,
  buildResponsiveAttrs,
  generateBlurPlaceholder,
  computeSizes,
  isOverBudget,
  estimateFormatSavings,
  suggestFormat,
  DEFAULT_WIDTHS,
  QUALITY_PRESETS,
  SIZE_BUDGETS,
} from '@/lib/performance/image-optimization';

// ============================================================================
// buildImageUrl
// ============================================================================

describe('buildImageUrl', () => {
  it('builds URL for internal image', () => {
    const url = buildImageUrl('/images/hero.jpg', 1200, 85);
    expect(url).toBe('/_next/image?url=%2Fimages%2Fhero.jpg&w=1200&q=85');
  });

  it('builds URL for external image', () => {
    const url = buildImageUrl('https://example.com/photo.jpg', 800, 75);
    expect(url).toContain('/_next/image?url=');
    expect(url).toContain(encodeURIComponent('https://example.com/photo.jpg'));
    expect(url).toContain('w=800');
    expect(url).toContain('q=75');
  });

  it('defaults quality to 75', () => {
    const url = buildImageUrl('/img.png', 640);
    expect(url).toContain('q=75');
  });
});

// ============================================================================
// buildSrcSet
// ============================================================================

describe('buildSrcSet', () => {
  it('generates srcset with width descriptors', () => {
    const srcSet = buildSrcSet('/img.jpg', [640, 1080], 80);
    expect(srcSet).toContain('640w');
    expect(srcSet).toContain('1080w');
    expect(srcSet).toContain('q=80');
    expect(srcSet.split(', ').length).toBe(2);
  });

  it('handles single width', () => {
    const srcSet = buildSrcSet('/img.jpg', [1920]);
    expect(srcSet.split(', ').length).toBe(1);
    expect(srcSet).toContain('1920w');
  });
});

// ============================================================================
// buildResponsiveAttrs
// ============================================================================

describe('buildResponsiveAttrs', () => {
  it('builds complete responsive attributes', () => {
    const attrs = buildResponsiveAttrs({
      src: '/hero.jpg',
      alt: 'Hero image',
      quality: 85,
    });
    expect(attrs.alt).toBe('Hero image');
    expect(attrs.loading).toBe('lazy');
    expect(attrs.decoding).toBe('async');
    expect(attrs.sizes).toBe('100vw');
    expect(attrs.srcSet).toContain('w');
    expect(attrs.src).toContain('/_next/image');
    expect(attrs.fetchPriority).toBeUndefined();
  });

  it('sets eager loading and sync decoding when not lazy', () => {
    const attrs = buildResponsiveAttrs({
      src: '/hero.jpg',
      alt: 'Hero',
      loading: 'eager',
    });
    expect(attrs.loading).toBe('eager');
    expect(attrs.decoding).toBe('sync');
  });

  it('sets fetchPriority when priority is true', () => {
    const attrs = buildResponsiveAttrs({
      src: '/hero.jpg',
      alt: 'Hero',
      priority: true,
    });
    expect(attrs.fetchPriority).toBe('high');
  });

  it('uses custom widths and sizes', () => {
    const attrs = buildResponsiveAttrs({
      src: '/thumb.jpg',
      alt: 'Thumbnail',
      widths: [640, 828],
      sizes: '50vw',
    });
    expect(attrs.sizes).toBe('50vw');
    expect(attrs.srcSet.split(', ').length).toBe(2);
  });
});

// ============================================================================
// generateBlurPlaceholder
// ============================================================================

describe('generateBlurPlaceholder', () => {
  it('returns a data URI', () => {
    const uri = generateBlurPlaceholder();
    expect(uri).toMatch(/^data:image\/svg\+xml;base64,/);
  });

  it('encodes valid SVG', () => {
    const uri = generateBlurPlaceholder(10, 10, '#ff0000');
    const base64 = uri.replace('data:image/svg+xml;base64,', '');
    const decoded = Buffer.from(base64, 'base64').toString('utf-8');
    expect(decoded).toContain('<svg');
    expect(decoded).toContain('width="10"');
    expect(decoded).toContain('height="10"');
    expect(decoded).toContain('fill="#ff0000"');
  });

  it('uses default dimensions', () => {
    const uri = generateBlurPlaceholder();
    const decoded = Buffer.from(uri.replace('data:image/svg+xml;base64,', ''), 'base64').toString();
    expect(decoded).toContain('width="8"');
    expect(decoded).toContain('height="8"');
  });
});

// ============================================================================
// computeSizes
// ============================================================================

describe('computeSizes', () => {
  it('returns 100vw for full layout', () => {
    expect(computeSizes('full')).toBe('100vw');
  });

  it('returns responsive sizes for half layout', () => {
    const sizes = computeSizes('half');
    expect(sizes).toContain('50vw');
    expect(sizes).toContain('100vw');
  });

  it('returns three breakpoints for third layout', () => {
    const sizes = computeSizes('third');
    expect(sizes).toContain('33vw');
    expect(sizes).toContain('50vw');
  });

  it('returns quarter sizes', () => {
    const sizes = computeSizes('quarter');
    expect(sizes).toContain('25vw');
    expect(sizes).toContain('50vw');
  });

  it('returns thumbnail sizes', () => {
    const sizes = computeSizes('thumbnail');
    expect(sizes).toContain('150px');
    expect(sizes).toContain('25vw');
  });
});

// ============================================================================
// isOverBudget
// ============================================================================

describe('isOverBudget', () => {
  it('returns true when over budget', () => {
    expect(isOverBudget(250_000, 'hero')).toBe(true);
    expect(isOverBudget(50_000, 'thumbnail')).toBe(true);
  });

  it('returns false when within budget', () => {
    expect(isOverBudget(100_000, 'hero')).toBe(false);
    expect(isOverBudget(10_000, 'thumbnail')).toBe(false);
  });

  it('returns false when exactly at budget', () => {
    expect(isOverBudget(200_000, 'hero')).toBe(false);
    expect(isOverBudget(30_000, 'thumbnail')).toBe(false);
  });
});

// ============================================================================
// estimateFormatSavings
// ============================================================================

describe('estimateFormatSavings', () => {
  it('estimates 50% savings for AVIF', () => {
    expect(estimateFormatSavings(100_000, 'avif')).toBe(50_000);
  });

  it('estimates 30% savings for WebP', () => {
    expect(estimateFormatSavings(100_000, 'webp')).toBe(30_000);
  });

  it('estimates 0 savings for JPEG/PNG', () => {
    expect(estimateFormatSavings(100_000, 'jpeg')).toBe(0);
    expect(estimateFormatSavings(100_000, 'png')).toBe(0);
  });
});

// ============================================================================
// suggestFormat
// ============================================================================

describe('suggestFormat', () => {
  it('suggests webp for images with transparency', () => {
    expect(suggestFormat(true, false)).toBe('webp');
    expect(suggestFormat(true, true)).toBe('webp');
  });

  it('suggests avif for photos without transparency', () => {
    expect(suggestFormat(false, true)).toBe('avif');
  });

  it('suggests webp for non-photo without transparency', () => {
    expect(suggestFormat(false, false)).toBe('webp');
  });
});

