describe('DEFAULT_WIDTHS', () => {
  it('has standard breakpoints', () => {
    expect(DEFAULT_WIDTHS).toContain(640);
    expect(DEFAULT_WIDTHS).toContain(1080);
    expect(DEFAULT_WIDTHS).toContain(1920);
    expect(DEFAULT_WIDTHS.length).toBeGreaterThanOrEqual(5);
  });

  it('is sorted ascending', () => {
    for (let i = 1; i < DEFAULT_WIDTHS.length; i++) {
      expect(DEFAULT_WIDTHS[i]).toBeGreaterThan(DEFAULT_WIDTHS[i - 1]);
    }
  });
});

